import{_ as a,o,c as n,a2 as t}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[INTEGRATION] F-05.2 — Endpoint SSE para Push de Eventos al Frontend","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-05.2_endpoint_sse.md","filePath":"backlog/F-05.2_endpoint_sse.md","lastUpdated":null}'),r={name:"backlog/F-05.2_endpoint_sse.md"};function i(s,e,d,c,l,p){return o(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="integration-f-05-2-—-endpoint-sse-para-push-de-eventos-al-frontend" tabindex="-1">[INTEGRATION] F-05.2 — Endpoint SSE para Push de Eventos al Frontend <a class="header-anchor" href="#integration-f-05-2-—-endpoint-sse-para-push-de-eventos-al-frontend" aria-label="Permalink to &quot;[INTEGRATION] F-05.2 — Endpoint SSE para Push de Eventos al Frontend&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-05 — Infraestructura y Conectividad</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Integration</code><strong>Impacta en:</strong> Equipo Backend (Laravel) + Equipo Infraestructura</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.1_setup_laravel_livewire.html">F-00.1</a></td><td>Base Laravel instalada</td></tr><tr><td><a href="./F-05.1_conexion_postgresql.html">F-05.1</a></td><td>Conexión PostgreSQL activa para <code>LISTEN</code>/<code>pg_notify</code></td></tr><tr><td><a href="./F-05.3_autenticacion_admin.html">F-05.3</a></td><td>Middleware <code>auth</code> para bloquear acceso SSE sin sesión válida</td></tr><tr><td><a href="./F-05.4_api_rest_crud.html">F-05.4</a></td><td>Ruta <code>GET /sse/logs</code> definida en <code>routes/web.php</code></td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Should</code></p><hr><p><strong>Descripción:</strong> Como desarrollador del sistema Quiero implementar un endpoint SSE en Laravel 12 que envíe actualizaciones de contadores al panel Livewire en tiempo real Para que el dashboard refleje cambios automáticamente sin polling desde el cliente</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Conexión SSE):</strong> Dado que el cliente Alpine.js abre la conexión al endpoint SSE via <code>EventSource</code>, cuando el servidor acepta la conexión, entonces responde con <code>Content-Type: text/event-stream</code> y mantiene la conexión abierta.</li><li>[ ] <strong>Escenario 2 (Evento push):</strong> Dado que n8n inserta un nuevo log en Postgres, cuando el servidor detecta el cambio (via pg_notify o polling), entonces envía un evento SSE con los nuevos contadores actualizados en menos de 2 s (NFR-LAT-03).</li><li>[ ] <strong>Escenario 3 (Autenticación):</strong> Dado que un cliente sin sesión válida solicita el endpoint SSE, cuando realiza la petición, entonces recibe redirección al login y la conexión no se establece (STRIDE I-API-01).</li><li>[ ] <strong>Escenario 4 (Desconexión limpia):</strong> Dado que el frontend cierra el tab o navega fuera, cuando la conexión SSE se cierra, entonces el servidor libera los recursos asociados sin memory leaks.</li><li>[ ] <strong>Requisito Técnico:</strong> Implementar con <code>StreamedResponse</code> de Laravel. Usar <code>pg_notify</code>/<code>LISTEN</code> de PostgreSQL para reactividad. El endpoint requiere middleware <code>auth</code> (sesión web de Laravel — <strong>no</strong> Sanctum, no hay tokens API en este proyecto). Configurar <code>php.ini</code> con <code>output_buffering = Off</code> para streaming correcto.</li></ul>',12)])])}const h=a(r,[["render",i]]);export{g as __pageData,h as default};
